const body = $input.first().json.body;

const githubUrl = body.github_url.trim().replace(/\/$/, '');
const githubParts = githubUrl.replace('https://github.com/', '').split('/');
const githubOwner = githubParts[0];
const githubRepo = githubParts[1];

const linkedinUrl = (body.linkedin_url || '').trim().replace(/\/$/, '');
const linkedinUsername = linkedinUrl.split('/in/')[1]?.replace('/', '') || '';

if (!githubOwner || !githubRepo) {
  throw new Error('Invalid GitHub URL format. Expected: https://github.com/username/repo');
}

return [{
  json: {
    github_owner: githubOwner,
    github_repo: githubRepo,
    github_url: githubUrl,
    linkedin_url: linkedinUrl,
    linkedin_username: linkedinUsername,
    tone: body.tone || 'professional',
    linkedin_access_token: body.linkedin_access_token || '',
    linkedin_user_id: body.linkedin_user_id || '',
    linkedin_profile_name: body.linkedin_profile_name || '',
    linkedin_profile_headline: body.linkedin_profile_headline || '',
    linkedin_profile_location: body.linkedin_profile_location || ''
  }
}];

const allItems = $input.all().map((item) => item.json);

const repoData =
  allItems.find((item) => item.full_name !== undefined && !Array.isArray(item)) || {};
const contributorsData = allItems.filter((item) => item.login !== undefined);
const commitsData = allItems.filter((item) => item.commit !== undefined);
const readmeItem =
  allItems.find((item) => item.encoding || item.download_url || item.content || item.body) || null;

const inputData = $('Input Parser').first().json;

function decodeReadme(item) {
  if (!item) return '';
  if (typeof item === 'string') return item;

  const raw = item.content || item.body || item.data || '';
  if (typeof raw !== 'string' || !raw) return '';

  if (String(item.encoding || '').toLowerCase() === 'base64') {
    try {
      return Buffer.from(raw.replace(/\n/g, ''), 'base64').toString('utf8');
    } catch {
      return raw;
    }
  }

  return raw;
}

function stripMarkdown(markdown) {
  return String(markdown || '')
    .replace(/```[\s\S]*?```/g, ' ')
    .replace(/`([^`]+)`/g, '$1')
    .replace(/!\[[^\]]*\]\([^)]+\)/g, ' ')
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '$1 $2')
    .replace(/^#{1,6}\s*/gm, '')
    .replace(/^\s*[-*+]\s+/gm, '')
    .replace(/^\s*\d+\.\s+/gm, '')
    .replace(/[>*_~]/g, ' ')
    .replace(/\r/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/[ \t]{2,}/g, ' ')
    .trim();
}

const readmeRaw = decodeReadme(readmeItem);
const readmePlain = stripMarkdown(readmeRaw);
const readmeLength = readmePlain.length;
const hasDemo =
  /(demo|walkthrough|preview|video|streamlit|vercel|netlify|deploy|live)/i.test(readmePlain) ||
  Boolean(repoData.homepage);

let githubScore = 0;
const flags = [];
const warnings = [];

if (repoData.fork === true) {
  flags.push('FORKED_REPO');
} else {
  githubScore += 26;
}

const contributorCount = contributorsData.length;
const ownerContributor = contributorsData.find(
  (contributor) =>
    contributor.login &&
    contributor.login.toLowerCase() === String(inputData.github_owner).toLowerCase()
);

if (contributorCount <= 1) {
  githubScore += 18;
} else if (contributorCount <= 3 && ownerContributor) {
  githubScore += 12;
  warnings.push('MULTI_CONTRIBUTOR');
} else {
  githubScore += 6;
  warnings.push('TEAM_PROJECT');
}

const commitCount = commitsData.length;
if (commitCount >= 15) {
  githubScore += 18;
} else if (commitCount >= 5) {
  githubScore += 12;
} else if (commitCount >= 1) {
  githubScore += 8;
} else {
  flags.push('INSUFFICIENT_COMMITS');
}

if (readmeLength >= 1200) {
  githubScore += 22;
} else if (readmeLength >= 400) {
  githubScore += 18;
} else if (readmeLength >= 150) {
  githubScore += 12;
  warnings.push('README_COULD_BE_BETTER');
} else if (readmeLength > 0) {
  githubScore += 6;
  warnings.push('MINIMAL_README');
} else {
  flags.push('NO_README');
}

const repoSize = Number(repoData.size || 0);
if (repoSize > 10) {
  githubScore += 10;
} else if (repoSize > 1) {
  githubScore += 6;
  warnings.push('SMALL_REPO');
} else {
  flags.push('EMPTY_REPO');
}

if ((repoData.stargazers_count || 0) > 0) {
  githubScore += Math.min(Number(repoData.stargazers_count || 0), 4);
}

if (hasDemo) {
  githubScore += 4;
}

if (Array.isArray(repoData.topics) && repoData.topics.length > 0) {
  githubScore += 2;
}

return [
  {
    json: {
      ...inputData,
      github_score: Math.min(githubScore, 100),
      github_flags: flags,
      github_warnings: warnings,
      repo_meta: {
        name: repoData.name || inputData.github_repo,
        full_name: repoData.full_name || `${inputData.github_owner}/${inputData.github_repo}`,
        description: repoData.description || '',
        language: repoData.language || 'Not specified',
        stars: repoData.stargazers_count || 0,
        created_at: repoData.created_at || '',
        updated_at: repoData.updated_at || '',
        homepage: repoData.homepage || '',
        topics: repoData.topics || [],
        is_fork: Boolean(repoData.fork),
        contributor_count: contributorCount,
        commit_count: commitCount,
        default_branch: repoData.default_branch || 'main',
        size: repoSize
      },
      readme_content: readmePlain,
      readme_raw: readmeRaw,
      has_demo_link: hasDemo
    }
  }
];

const data = $('GitHub Validation Scorer').first().json;

const linkedinUrl = String(data.linkedin_url || '').trim();
const name = String(data.linkedin_profile_name || '').trim() || 'Professional';
const headline = String(data.linkedin_profile_headline || '').trim() || 'IT Professional';
const location = String(data.linkedin_profile_location || '').trim();

let linkedinScore = 35;
const linkedinWarnings = [];

if (linkedinUrl) {
  linkedinScore += 15;
} else {
  linkedinWarnings.push('LINKEDIN_URL_MISSING');
}

if (name && name !== 'Professional') {
  linkedinScore += 20;
} else {
  linkedinWarnings.push('LINKEDIN_NAME_MISSING');
}

if (headline && headline !== 'IT Professional') {
  linkedinScore += 20;
} else {
  linkedinWarnings.push('LINKEDIN_HEADLINE_MISSING');
}

if (location) {
  linkedinScore += 10;
}

return [
  {
    json: {
      ...data,
      linkedin_score: Math.min(linkedinScore, 100),
      linkedin_flags: [],
      linkedin_warnings: linkedinWarnings,
      linkedin_scrape_success: Boolean(linkedinUrl),
      linkedin_profile: {
        name,
        headline,
        location,
        connection_count: 0,
        profile_exists: Boolean(linkedinUrl)
      }
    }
  }
];

const data = $input.first().json;

const githubWeighted = (data.github_score / 100) * 75;
const linkedinWeighted = (data.linkedin_score / 100) * 25;
const totalScore = Math.round(githubWeighted + linkedinWeighted);

let trustLevel = '';
let trustBadge = '';
let proceedToGeneration = false;
let rejectionReason = '';

const allFlags = [...(data.github_flags || []), ...(data.linkedin_flags || [])];
const warningCodes = [...(data.github_warnings || []), ...(data.linkedin_warnings || [])];

if (allFlags.includes('FORKED_REPO')) {
  trustLevel = 'REJECTED';
  rejectionReason =
    'This repository appears to be a fork. DevPost Pro only generates content for original work.';
} else if (allFlags.includes('EMPTY_REPO')) {
  trustLevel = 'REJECTED';
  rejectionReason =
    'This repository appears to be empty or too small to analyze meaningfully. Add more project material and try again.';
} else if (allFlags.includes('INSUFFICIENT_COMMITS')) {
  trustLevel = 'REJECTED';
  rejectionReason =
    'This repository does not have enough commit history yet. Add at least one meaningful commit before generating posts.';
} else if (totalScore >= 80) {
  trustLevel = 'HIGH';
  trustBadge = 'VERIFIED';
  proceedToGeneration = true;
} else if (totalScore >= 60) {
  trustLevel = 'MEDIUM';
  trustBadge = 'STANDARD';
  proceedToGeneration = true;
} else if (totalScore >= 45) {
  trustLevel = 'LOW';
  trustBadge = 'BASIC';
  proceedToGeneration = true;
} else {
  trustLevel = 'REJECTED';
  rejectionReason = `This project scored ${totalScore}/100 on the credibility check. Strengthen the README, commit history, or project substance and try again.`;
}

const warningMap = {
  MULTI_CONTRIBUTOR: 'Multiple contributors detected',
  TEAM_PROJECT: 'Team project detected',
  README_COULD_BE_BETTER: 'README could be more detailed',
  MINIMAL_README: 'README is minimal',
  SMALL_REPO: 'Repository is still small',
  LINKEDIN_URL_MISSING: 'LinkedIn URL is missing',
  LINKEDIN_NAME_MISSING: 'Profile name is missing',
  LINKEDIN_HEADLINE_MISSING: 'Profile headline is missing'
};

const warningMessages = [...new Set(warningCodes.map((code) => warningMap[code] || code))];

const readmePass = !allFlags.includes('NO_README') && !warningCodes.includes('MINIMAL_README');

const scoreBreakdown = {
  total: totalScore,
  github_component: Math.round(githubWeighted),
  linkedin_component: Math.round(linkedinWeighted),
  checks: {
    is_original_work: !allFlags.includes('FORKED_REPO'),
    solo_or_lead_author: !warningCodes.includes('TEAM_PROJECT'),
    has_commit_history: !allFlags.includes('INSUFFICIENT_COMMITS'),
    readme_quality: readmePass,
    linkedin_profile_real: Boolean(data.linkedin_url)
  },
  warnings: warningMessages
};

return [
  {
    json: {
      ...data,
      trust_score: totalScore,
      trust_level: trustLevel,
      trust_badge: trustBadge,
      proceed_to_generation: proceedToGeneration,
      rejection_reason: rejectionReason,
      score_breakdown: scoreBreakdown
    }
  }
];

const data = $input.first().json;

return [{
  json: {
    status: 'rejected',
    trust_score: data.trust_score,
    score_breakdown: data.score_breakdown,
    rejection_reason: data.rejection_reason,
    repo_meta: data.repo_meta,
    linkedin_profile: data.linkedin_profile
  }
}];

const data = $input.first().json;
const readme = String(data.readme_content || '');
const repoMeta = data.repo_meta || {};

function cleanSentence(text, maxLength = 220) {
  return String(text || '')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, maxLength)
    .replace(/[,:;.\- ]+$/, '');
}

function dedupe(values) {
  return [...new Set(values.filter(Boolean))];
}

const techPatterns = {
  languages: ['Python', 'JavaScript', 'TypeScript', 'Java', 'Go', 'Rust', 'C++', 'C#', 'PHP', 'Ruby', 'Swift', 'Kotlin', 'R', 'Scala'],
  frontend: ['React', 'Next.js', 'Vue', 'Angular', 'Svelte', 'Tailwind', 'HTML', 'CSS', 'Bootstrap'],
  backend: ['Node.js', 'Express', 'FastAPI', 'Django', 'Flask', 'Spring', 'NestJS', 'Laravel'],
  databases: ['PostgreSQL', 'MySQL', 'MongoDB', 'Redis', 'SQLite', 'Supabase', 'Firebase', 'Pinecone', 'Chroma'],
  cloud: ['AWS', 'Azure', 'GCP', 'Vercel', 'Netlify', 'Docker', 'Kubernetes', 'Streamlit'],
  ai_ml: ['OpenAI', 'LangChain', 'RAG', 'LLM', 'Gemini', 'GPT', 'PyTorch', 'TensorFlow', 'scikit-learn', 'pandas', 'numpy'],
  tools: ['GitHub Actions', 'REST API', 'GraphQL', 'OAuth', 'JWT', 'n8n']
};

const combinedText = [
  readme,
  repoMeta.description || '',
  repoMeta.language || '',
  Array.isArray(repoMeta.topics) ? repoMeta.topics.join(' ') : ''
]
  .join('\n')
  .toLowerCase();

const detectedTech = {};
for (const [category, techs] of Object.entries(techPatterns)) {
  const found = techs.filter((tech) => combinedText.includes(tech.toLowerCase()));
  if (found.length > 0) {
    detectedTech[category] = found;
  }
}

if (
  repoMeta.language &&
  !Object.values(detectedTech)
    .flat()
    .map((tech) => tech.toLowerCase())
    .includes(String(repoMeta.language).toLowerCase())
) {
  detectedTech.languages = [...(detectedTech.languages || []), repoMeta.language];
}

const techStackFlat = dedupe(Object.values(detectedTech).flat());

const rawLines = readme
  .split('\n')
  .map((line) => line.trim())
  .filter(Boolean);

const proseLines = rawLines.filter(
  (line) =>
    !line.startsWith('#') &&
    !/^[-*+]\s/.test(line) &&
    !/^\d+\.\s/.test(line) &&
    line.length > 30
);

const bulletLines = rawLines
  .filter((line) => /^[-*+]\s/.test(line))
  .map((line) => cleanSentence(line.replace(/^[-*+]\s*/, ''), 100))
  .filter((line) => line.length > 12);

const summarySeed =
  proseLines.slice(0, 3).join(' ') || repoMeta.description || repoMeta.name || 'GitHub project';

const goalLine =
  proseLines.find((line) =>
    /(helps|solve|automate|designed to|built to|allows|enables|streamline|platform|tool|dashboard)/i.test(line)
  ) || summarySeed;

const audienceSource = [repoMeta.description || '', ...proseLines].join(' ');
const audienceMatch = audienceSource.match(/\bfor\s+([A-Za-z0-9,&/()\- ]{4,80})/i);
const targetUsers = audienceMatch
  ? cleanSentence(audienceMatch[1], 70)
  : 'IT and CS professionals';

const featureCandidates = dedupe([
  ...bulletLines,
  ...proseLines
    .filter((line) => /(feature|supports|includes|pipeline|workflow|dashboard|automation|analysis|generation|upload|deployment|api)/i.test(line))
    .map((line) => cleanSentence(line, 100))
]);

const keyFeatures = featureCandidates.slice(0, 3);

const proofPoints = dedupe([
  repoMeta.language && repoMeta.language !== 'Not specified' ? `Built with ${repoMeta.language}` : '',
  techStackFlat.length ? `Uses ${techStackFlat.slice(0, 3).join(', ')}` : '',
  Number(repoMeta.commit_count || 0) > 0 ? `${repoMeta.commit_count} commits on GitHub` : '',
  Number(repoMeta.contributor_count || 0) > 0
    ? `${repoMeta.contributor_count} contributor${Number(repoMeta.contributor_count) === 1 ? '' : 's'}`
    : '',
  data.has_demo_link ? 'Demo or deployment link available' : '',
  repoMeta.homepage ? `Homepage: ${repoMeta.homepage}` : ''
]).slice(0, 4);

const projectContext = {
  headline: cleanSentence(repoMeta.name || summarySeed, 80),
  target_users: targetUsers,
  value_prop: cleanSentence(goalLine || summarySeed, 180),
  key_features: keyFeatures,
  proof_points: proofPoints,
  demo_url: repoMeta.homepage || '',
  README_excerpt: cleanSentence(summarySeed, 260)
};

return [
  {
    json: {
      ...data,
      tech_stack: detectedTech,
      tech_stack_flat: techStackFlat,
      project_summary: cleanSentence(summarySeed, 260),
      readme_cleaned: readme.slice(0, 5000),
      project_context: projectContext
    }
  }
];

const data = $input.first().json;

function escapeHtml(value) {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

const creative = data.generated_posts?.creative_brief || {};
const highlights = [
  creative.highlight_1,
  creative.highlight_2,
  creative.highlight_3
].filter(Boolean).slice(0, 3);

const imageCardData = {
  title: creative.headline || data.repo_meta.name,
  description: creative.subheadline || data.project_summary,
  tech_stack: (data.tech_stack_flat || []).slice(0, 6),
  author_name: data.linkedin_profile.name,
  author_role: data.linkedin_profile.headline,
  language: data.repo_meta.language,
  stars: data.repo_meta.stars,
  trust_badge: data.trust_badge,
  trust_score: data.trust_score,
  github_url: data.github_url,
  proof_line: creative.proof_line || '',
  audience: creative.audience || '',
  highlights
};

const badgeColor =
  data.trust_badge === 'VERIFIED'
    ? '#059669'
    : data.trust_badge === 'STANDARD'
      ? '#d97706'
      : '#ea580c';

const badgeText =
  data.trust_badge === 'VERIFIED'
    ? 'Verified Work'
    : data.trust_badge === 'STANDARD'
      ? 'Authenticated'
      : 'Profile-backed';

const techBadges = imageCardData.tech_stack
  .map(
    (tech) =>
      `<span style="background:#dbeafe;color:#1d4ed8;padding:8px 14px;border-radius:999px;font-size:15px;font-weight:600">${escapeHtml(tech)}</span>`
  )
  .join('');

const highlightBlocks = highlights
  .map(
    (item) =>
      `<div style="flex:1;min-width:0;background:rgba(255,255,255,0.06);border:1px solid rgba(148,163,184,0.24);border-radius:18px;padding:18px"><div style="color:#e2e8f0;font-size:18px;font-weight:600;line-height:1.35">${escapeHtml(item)}</div></div>`
  )
  .join('');

const imageHtml = `<div style="width:1200px;height:630px;background:linear-gradient(135deg,#0f172a 0%,#172554 45%,#1e293b 100%);padding:52px;display:flex;flex-direction:column;justify-content:space-between;font-family:Inter,Segoe UI,Arial,sans-serif;box-sizing:border-box">
  <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:24px">
    <div>
      <div style="color:#93c5fd;font-size:18px;font-weight:700;letter-spacing:0.08em;text-transform:uppercase">DevPost Pro</div>
      <div style="color:#94a3b8;font-size:18px;margin-top:12px">${escapeHtml(creative.eyebrow || 'Project spotlight')}</div>
    </div>
    <div style="background:${badgeColor};color:white;padding:10px 18px;border-radius:999px;font-size:15px;font-weight:700">${escapeHtml(badgeText)}</div>
  </div>

  <div style="display:flex;flex-direction:column;gap:18px">
    <h1 style="margin:0;color:white;font-size:54px;line-height:1.05;font-weight:800;max-width:920px">${escapeHtml(imageCardData.title).slice(0, 120)}</h1>
    <p style="margin:0;color:#cbd5e1;font-size:24px;line-height:1.4;max-width:940px">${escapeHtml(imageCardData.description).slice(0, 180)}</p>
    ${imageCardData.audience ? `<div style="color:#93c5fd;font-size:18px;font-weight:600">Built for ${escapeHtml(imageCardData.audience).slice(0, 80)}</div>` : ''}
  </div>

  <div style="display:flex;flex-direction:column;gap:18px">
    ${highlightBlocks ? `<div style="display:flex;gap:16px">${highlightBlocks}</div>` : ''}
    <div style="display:flex;justify-content:space-between;align-items:flex-end;gap:24px">
      <div>
        <div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:16px">${techBadges}</div>
        <div style="color:#e2e8f0;font-size:20px;font-weight:600">${escapeHtml(imageCardData.author_name)}</div>
        <div style="color:#94a3b8;font-size:18px;margin-top:6px">${escapeHtml(imageCardData.author_role)}</div>
      </div>
      <div style="text-align:right;max-width:360px">
        <div style="color:#cbd5e1;font-size:18px;font-weight:600">${escapeHtml(imageCardData.proof_line).slice(0, 90)}</div>
        <div style="color:#64748b;font-size:16px;margin-top:8px">${escapeHtml(data.repo_meta.name)}</div>
      </div>
    </div>
  </div>
</div>`;

return [
  {
    json: {
      ...data,
      image_card: {
        html: imageHtml,
        data: imageCardData
      }
    }
  }
];

const data = $input.first().json;

if (data.status === 'rejected') {
  return [{ json: data }];
}

return [
  {
    json: {
      status: 'success',
      trust: {
        score: data.trust_score,
        level: data.trust_level,
        badge: data.trust_badge,
        breakdown: data.score_breakdown
      },
      profile: {
        github: {
          repo_name: data.repo_meta.name,
          description: data.repo_meta.description,
          language: data.repo_meta.language,
          stars: data.repo_meta.stars,
          contributors: data.repo_meta.contributor_count,
          commits: data.repo_meta.commit_count,
          is_fork: data.repo_meta.is_fork,
          url: data.github_url
        },
        linkedin: data.linkedin_profile
      },
      tech_stack: data.tech_stack,
      tech_stack_flat: data.tech_stack_flat,
      posts: {
        technical: { ...data.generated_posts.post_technical, id: 'technical' },
        story: { ...data.generated_posts.post_story, id: 'story' },
        announcement: { ...data.generated_posts.post_announcement, id: 'announcement' }
      },
      recruiter_scores: data.generated_posts.recruiter_score,
      image_card: data.image_card,
      generated_at: data.generation_timestamp
    }
  }
];

const mistralResponse = $input.first().json;
const prevData = $('Tech Stack Extractor').first().json;

// Mistral response path
const responseText = mistralResponse.choices[0].message.content;

let posts;
try {
  const cleaned = responseText.replace(/```json|```/g, '').trim();
  posts = JSON.parse(cleaned);
} catch(e) {
  const jsonMatch = responseText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    posts = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('Mistral did not return valid JSON. Response: ' + responseText.substring(0, 300));
  }
}

return [{
  json: {
    ...prevData,
    generated_posts: posts,
    generation_timestamp: new Date().toISOString()
  }
}];

const data = $input.first().json;

const prompt = `You are an expert LinkedIn content strategist for IT professionals. Generate 3 LinkedIn posts for this developer's GitHub project. Return ONLY raw JSON — no markdown, no backticks, no explanation.

PROFESSIONAL CONTEXT:
- Name: ${data.linkedin_profile?.name || 'Professional'}
- Role: ${data.linkedin_profile?.headline || 'IT Professional'}
- Location: ${data.linkedin_profile?.location || ''}
- Tone: ${data.tone || 'professional'}

PROJECT DATA:
- Repo: ${data.repo_meta?.name || ''}
- Description: ${data.repo_meta?.description || ''}
- Language: ${data.repo_meta?.language || ''}
- Stars: ${data.repo_meta?.stars || 0}
- Tech stack: ${(data.tech_stack_flat || []).join(', ')}
- Summary: ${data.project_summary || ''}
- README excerpt: ${(data.readme_cleaned || '').substring(0, 1500)}

Return exactly this JSON structure with no extra text:
{
  "post_technical": {
    "content": "150-200 word technical deep-dive post. Bold hook. Explain problem solved and tech decisions. End with a question.",
    "hashtags": ["#tag1", "#tag2", "#tag3", "#tag4", "#tag5"],
    "post_type": "Technical Deep-Dive",
    "best_time_to_post": "Tuesday-Thursday 8-10am",
    "expected_reach": "High engagement from developers"
  },
  "post_story": {
    "content": "150-200 word lessons-learned narrative. Personal challenge. The journey. Key takeaway.",
    "hashtags": ["#tag1", "#tag2", "#tag3", "#tag4", "#tag5"],
    "post_type": "Lessons Learned",
    "best_time_to_post": "Monday 9am or Friday 12pm",
    "expected_reach": "High engagement from career-focused audience"
  },
  "post_announcement": {
    "content": "100-150 word project announcement. Lead with impact. Accessible to non-technical readers. CTA to check repo.",
    "hashtags": ["#tag1", "#tag2", "#tag3", "#tag4", "#tag5"],
    "post_type": "Project Announcement",
    "best_time_to_post": "Wednesday 10am-12pm",
    "expected_reach": "Broadest reach"
  },
